pub fn reorder_list(head: &mut Option<Box<ListNode>>) {
    if head.is_none() || head.as_ref().unwrap().next.is_none() {
        return;
    }
    let mut slow = head.clone();
    let mut fast = head.clone();
    while fast.as_ref().unwrap().next.is_some() && fast.as_ref().unwrap().next.as_ref().unwrap().next.is_some() {
        slow = slow.unwrap().next;
        fast = fast.unwrap().next.unwrap().next;
    }
    let mut prev: Option<Box<ListNode>> = None;
    let mut curr = slow.unwrap().next;
    while curr.is_some() {
        let next = curr.as_mut().unwrap().next.take();
        curr.as_mut().unwrap().next = prev;
        prev = curr;
        curr = next;
    }
    let mut first = head.clone();
    let mut second = prev;
    while second.is_some() {
        let tmp1 = first.as_mut().unwrap().next.take();
        let tmp2 = second.as_mut().unwrap().next.take();
        first.as_mut().unwrap().next = second;
        second.as_mut().unwrap().next = tmp1;
        first = first.unwrap().next;
        second = tmp2;
    }
    *head = first;
}

