pub fn rotate_right(head: Option<Box<ListNode>>, k: i32) -> Option<Box<ListNode>> {
    if head.is_none() || head.as_ref().unwrap().next.is_none() || k == 0 {
        return head;
    }
    let mut length = 1;
    let mut tail = &head;
    while tail.as_ref().unwrap().next.is_some() {
        tail = &tail.as_ref().unwrap().next;
        length += 1;
    }
    let k = k % length;
    if k == 0 {
        return head;
    }
    let mut head = head;
    tail.as_ref().unwrap().next.as_ref().map(|n| {
        let tail_next = n.next.take();
        tail_next
    });
    let mut tail_ref = &mut head;
    for _ in 0..length - 1 {
        tail_ref = &mut tail_ref.as_mut().unwrap().next;
    }
    let mut new_head = tail_ref.as_mut().unwrap().next.take();
    let mut curr = &mut new_head;
    for _ in 0..length - k - 1 {
        curr = &mut curr.as_mut().unwrap().next;
    }
    curr.as_mut().unwrap().next = head;
    new_head
}
